import javax.sound.midi.*;
public class MiniMusicPlayer1 { 

 public static void main(String[] args) { 
 try {
 Sequencer sequencer = MidiSystem.getSequencer(); 
 sequencer.open();


 Sequence seq = new Sequence(Sequence.PPQ, 4);
 Track track = seq.createTrack(); 

 for (int i = 5; i < 61; i+= 4) {

 track.add(makeEvent(144,1,i,100,i));
 track.add(makeEvent(128,1,i,100,i + 2));
 } // end loop

 sequencer.setSequence(seq);
 sequencer.setTempoInBPM(220);
 sequencer.start();
 } catch (Exception ex) {ex.printStackTrace();}
 } // close main
 public static MidiEvent makeEvent(int comd, int chan, int one, int two, int tick) {
 MidiEvent event = null;
 try {
 ShortMessage a = new ShortMessage();
 a.setMessage(comd, chan, one, two);
 event = new MidiEvent(a, tick);

 }catch(Exception e) { }
 return event;
 }
} // close class
make (and open) a sequencer
make a sequence 
and a track
make a bunch of events to make the notes keep 
going up (from piano note 5 to piano note 61) 
don’t forget the import
call our new makeEvent() method to make the 
message and event, then add the result (the 
MidiEvent returned from makeEvent()) to 
the track. These are NOTE ON (144) and 
NOTE OFF (128) pairs
start it running
There’5 no event handling or graphics here, just a sequence of 15 
notes that go up the scale. The point of this code is simply to learn 
how to use our new makeEvent() method. The code for the next 
two versions is much smaller and simpler thanks to this method.
Example: how to use the new static 
makeEvent() method

